    ///                          · FrameMetadata.crop_width
    ///      pivot_sensor_px_y = FrameMetadata.crop_y
    ///                        + (camera_intrinsic_matrix\[1, 2\] / frame_height)
    ///                          · FrameMetadata.crop_height
    ///
